import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"正义骑士套装","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/正义骑士套装.md","filePath":"4.资源分区/7.物品与装备/6.套装/正义骑士套装.md"}'),s={name:"4.资源分区/7.物品与装备/6.套装/正义骑士套装.md"};function o(d,b,_,l,i,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"正义骑士套装",tabindex:"-1"},[t("正义骑士套装 "),r("a",{class:"header-anchor",href:"#正义骑士套装","aria-label":'Permalink to "正义骑士套装"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),n('<h1 id="正义骑士套装-1" tabindex="-1">正义骑士套装 <a class="header-anchor" href="#正义骑士套装-1" aria-label="Permalink to &quot;正义骑士套装&quot;">​</a></h1><p>正义骑士套装<br> 描述：惜别被破，跪倒在地，怀中小镰刀掉落。<br> 刻下的话语，涌上心头。<br> 将我的繁文琐节，弃置于此。<br> “啊，原来你一直与我同在！”</p><p>脑袋尖尖头巾<br> 价格：D+500<br> 分类：头盔<br> 描述：曾被称为奴隶头巾，但是脑袋尖尖。其实并不是特别强力的装备，胜在重量较轻。<br> 效果：提供4/4的盔甲防御，与其他盔甲防御叠加计算。此外，由于重量轻盈，穿戴者受到的盔甲减值将会下降2点，基础移动速度提升15米。</p><p>肚子圆圆甲<br> 价格：D+500<br> 分类：重甲<br> 防御：10/10 盔甲减值：2<br> 特殊属性：无<br> 描述：向天使宣誓忠诚的骑士盔甲，但是肚子圆圆。<br> 肚子圆圆：减伤，正是成为盔甲的理由。穿戴者获得2DR/法破的减伤能力。</p><p>宠爱戒指<br> 价格：D+500<br> 描述：女神的宠爱犹如蝴蝶般飘忽不定，正如同你可以通过不停切戒指恢复精力一样。<br> 效果：穿戴者在耐力上获得1DP加值，同时获得2点异常点数治疗（医疗点48），但只能治疗疲乏异常不良点数，即使承受了疲乏异常不良点数也不会获得减值。</p><p>刺针臂甲<br> 价格：D+500<br> 描述：翻滚就会固定造成伤害的臂甲。<br> 效果：你在购买时可以选择其中一个效果获得。<br> ·穿戴者获得1点基于盔甲防御的反伤效果，伤害类型为物理穿刺。<br> ·穿戴者在移动后进行的攻击，造成伤害时额外追加2点物理穿刺伤害。</p><p>哈维尔腿甲<br> 价格：D+500<br> 描述：被比喻成巨岩的重装腿甲，以极高防御力受到称赞，但非常沉重。<br> 效果：提供5/5的盔甲防御，与其他盔甲防御叠加计算，获得基于盔甲防御的【封闭1】。<br> 只要穿戴了哈维尔腿甲，你就还会在耐力上获得1DP加值。</p><p>左弓机关枪<br> 价格：D+500<br> 分类：弓<br> 武器伤害： 7L<br> 武器特性：【高速5】【贯穿】【连射】<br> 伤害类型：物理-穿刺<br> 基础射程：100<br> 容量：50（无限子弹）<br> 体积：4<br> 描述：虽然主神已经修复了这个BUG，然而只有保留连发能力，你才知道这是左弓机关枪。<br> 连发机关枪：该武器具有【无限子弹】特性。</p><p>半叶大刀<br> 价格：D+500<br> 分类：刀<br> 武器伤害：7L<br> 武器特性：【破甲1】【重型武器】<br> 伤害类型：物理-挥砍<br> 体积：4<br> 描述：源自异邦的长柄大刀，整体以铜铸造，十分沉重。<br> 所谓半叶，指的是大刀刀身的形状，据说是以叶脉的模样设计而成，因为主神修复了特性的缘故，该武器只剩下了纪念意义。</p><p>无限连飞舞：使用者获得了一个新的招式【轮旋斩】，是将武器高举头上，快速旋转后，再横扫敌人的战技，可以顺势使出普通攻击或重攻击。<br> 标准动作使用【轮旋斩】，你可以攻击触及范围内的所有敌人，同时在本次攻击中获得1DP加值与1点附加成功数。</p><p>黑骑士盾<br> 价格：D+500<br> 分类：盾<br> 武器伤害：2L<br> 武器特性：【格挡9】<br> 伤害类型：物理-钝击<br> 体积：3<br> 描述：重量合适的中型盾牌，抗性综合最高。<br> 属性抵抗：持有者获得1点全能量抗性，和在耐力上的1DP加值。</p><p>神秘小零食<br> 价格：C+1000<br> 描述：不死人的神秘小零食<br> 效果：在购买时选择以下两种效果之一获得。<br> ·使用一个花招动作，你可以将小零食结合在接下来的一次攻击中，伤害转为毒素伤害，使受到伤害的目标立刻红温，在接下来的一场景内必须以攻击你为第一目标，这是一个完美来源的C级胁迫效果（即要求B级免疫）。</p><p>·使用一个标准动作，你进行一次量大管饱的攻击，将小零食视为6L的投掷武器进行抛射，本次攻击同时作用于投掷范围扇形一面的所有单位（不分敌我），因此本次投掷距离还会翻倍计算。<br> 一旦攻击造成了伤害，被命中的目标立刻红温，在接下来的一场景内必须以攻击你为第一目标，这是一个C级心灵来源的胁迫效果。<br> 本次伤害视为毒素伤害，同时造成2点反胃不良状态点数，不可豁免可叠加。</p><p>原素瓶<br> 价格：C+1000<br> 描述：原素瓶，果粒橙，不死人的最爱。<br> 效果：原素瓶中装有5口果粒橙，果粒橙会在你进行长休息后自动回满。<br> 持有者可以使用自由动作饮下一口果粒橙，获得持续一场景的快速医疗1（医疗点12），或者以一个花招动作豪迈的饮下所有的果粒橙，获得持续一场景的快速医疗5（医疗点60）。<br> 在快速医疗生效期间，你的耐力检定获得1DP加值。<br> 选开：如果你购买了身份专长：不死人，则你可以在篝火处执行短休的时候立刻将果粒橙补满，每天只能因为这个效果额外填补一次果粒橙。</p><p>咒死飞刀<br> 价格：A+4000<br> 描述：传说中的里技·咒死飞刀，效果就是和名字一样的恐怖。<br> 效果：咒死飞刀是消耗品，在购买时一次性获得20把咒死飞刀。<br> 咒死飞刀是0L的武器，每轮只能投掷一把，但投掷只需要一个自由动作，射程范围等同使用者的敏感范围，受害者需要以强韧检定进行豁免攻击成功数，豁免失败立刻承受A级诅咒来源的即死效果。<br> 使用者也可以选择这次攻击同时命中射程1/4范围内的所有敌人。</p><p>环取直剑<br> 价格：A+4000<br> 分类：镰刀<br> 武器伤害：26A<br> 武器特性：【轻灵】【破甲1】<br> 伤害类型：负能量/黑暗伤害<br> 体积：2<br> 描述：这不是小镰刀，这是弯曲的环直……似乎忘记了什么，这段记忆……被取消了。<br> 锋利质变：这把武器攻击必须使用不附带任何招式的标准动作，但伤害造成韧性伤害。如果你已经购买了神秘小零食，则还会附带等同攻击成功数的毒素不良点数，强韧豁免，可叠加。</p><p>翻滚无敌帧：每轮一次，你在受到攻击时可以反射动作进行一次移动，同时在应对这次攻击时所受伤害减半。</p><p>暗松脂：因浸泡人类体液腐烂的焦黑松脂，可以让武器暂时强化暗属性，因此该武器的伤害是负能量/黑暗伤害，使用这个效果需要在战斗开始使以自由动作进行擦刀。</p><p>【2件套·D】解锁“超级马拉松”<br> 你的移动速度提升15米。<br> 【4件套·D】解锁“洋葱汤”<br> 你获得1点开快速医疗，医疗点12。<br> 【6件套·D】解锁“翻滚”<br> 你失去2/4件D级套提供的额外特性，获得一个新的效果：翻滚。<br> 你可以使用一个移动动作，消耗1点意志力觉醒前世记忆，随后在接下来的一场景内，你可以在回合外使用反射动作进行一次翻滚移动，移动速度为你的基础移速，但这次翻滚会消耗你的一个标准动作。<br> 在觉醒前世记忆期间，你每轮额外获得2点AP，只能用于翻滚或填补标准动作AP，你无法在同一轮内使用这2AP进行两次标准动作的攻击。</p><p>【2件套·C】解锁“胜利的渴望”<br> 即使你的生命值被严重伤害填满也不会昏迷，同时获得1点吸血与1点生命值上限的提升。<br> 此外，由于你的血液中流淌的是对胜利的渴望，你无法与任何人的血型匹配。</p><p>下属技艺<br> 拔线<br> 价格：500<br> 描述：网络发生波动，正道骑士返回它的世界了！<br> 效果：无论当前你处于任何状态，都可以宣言“拔线”，立刻不可避免的死亡，且影片内不可因任何方式复活。在场的所有人都将会看到一行提示[发生联机问题]，这个文字提示只会出现一轮。</p><p>特殊，你可以在建卡时花费1点专长点来获得该技艺。</p><p>幻肢捉迷藏<br> 价格：C+1000<br> 描述：嘻嘻，我一定要活下去。<br> 效果：整轮动作使用，只有才你的生命值被严重伤害填满才能生效，你立刻获得持续一场景的B级魔幻本质侦测能力。</p><p>解锁“武 魂 真 身”<br> 价格：A+4000<br> 这个效果每影片只会生效一次。<br> 当使用环取直剑时，你可以消费一个标准动作为武器附魔，使武器伤害变为火焰能量伤害，以下效果必须在附魔后才会生效。<br> 在你死亡后，将立刻原地使用CE满状态复活一次，这是一个A级别、信息来源的复活效果，并从怀里掏出湿濡小镰刀（等同环取直剑），你使用湿濡小镰刀时视为额外获得三个只能用来攻击的标准动作，且每轮在回合外可以进行一次翻滚，翻滚等同使用反射动作执行了一次移动，但不消耗任何AP，持续一场景。当这一场景结束后，你会因为CE修改而被封号导致这一场影片内无法使用任何方式进行复活，仅能在主神空间以朝生暮死规则进行复活。<br> 湿濡小镰刀造成的伤害为负能量/黑暗伤害。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',26)])])}const P=p(s,[["render",o]]);export{h as __pageData,P as default};
